export const authOptions: NextAuthOptions = {
  // Include user.id and username on session
  callbacks: {
    session({ session, user }) {
      if (session.user) {
        session.user.id = user.id;
        // `user.username` is populated by the GitHubProvider profile() below
        session.user.username = user.username ?? null;
      }
      return session;
