import { createProtectedRouter } from "./protected-router";

/**
 * Protected router that exposes the currently signed-in user's profile data.
 * All queries here require an active session — unauthenticated callers receive
 * a TRPC UNAUTHORIZED error (enforced by the middleware in createProtectedRouter).
 *
 * The session already contains the GitHub avatar (`image`) and display name
 * (`name`) because NextAuth maps those fields from the GitHub OAuth profile.
 * The GitHub login/username (`username`) is stored via the custom profile()
 * mapping in the NextAuth config and surfaced through the session callback.
 */
export const userRouter = createProtectedRouter().query("getProfile", {
  resolve({ ctx }) {
    const { id, name, email, image, username } = ctx.session.user;
    return { id, name, email, image, username };
  },
});

