// src/pages/profile.tsx
import type { NextPage } from "next";
import Head from "next/head";
import Image from "next/image";
import { signOut, useSession } from "next-auth/react";
import { trpc } from "../utils/trpc";
import GitHubSignInButton from "../components/GitHubSignInButton";

/**
 * Profile page – shows the signed-in user's GitHub avatar, display name,
 * login (username) and email via the `user.getProfile` tRPC query.
 *
 * If the user is not signed in they are presented with the GitHub sign-in
 * button instead.
 */
const ProfilePage: NextPage = () => {
  return (
    <>
      <Head>
        <title>Profile – Create T3 App</title>
        <meta name="description" content="Your GitHub profile" />
        <link rel="icon" href="/favicon.ico" />
      </Head>

      <main className="container mx-auto flex min-h-screen flex-col items-center justify-center p-4">
        <h1 className="mb-8 text-4xl font-extrabold text-gray-700">
          Your <span className="text-purple-300">Profile</span>
        </h1>

        <ProfileCard />
      </main>
    </>
  );
};

// ---------------------------------------------------------------------------
// ProfileCard – handles both the signed-in and signed-out states
// ---------------------------------------------------------------------------

const ProfileCard: React.FC = () => {
  const { data: sessionData, status } = useSession();

  // Only fire the tRPC query when we know the user is authenticated.
  // `enabled: false` while loading avoids a flash of the UNAUTHORIZED error.
  const { data: profile, isLoading: profileLoading } = trpc.useQuery(
    ["user.getProfile"],
    { enabled: status === "authenticated" },
  );

  // ── Not signed in ──────────────────────────────────────────────────────────
  if (status === "unauthenticated") {
    return (
      <div className="flex flex-col items-center gap-4 rounded-xl border-2 border-gray-300 p-8 shadow-md">
        <p className="text-lg text-gray-600">
          Sign in with GitHub to view your profile.
        </p>
        <GitHubSignInButton />
      </div>
    );
  }

  // ── Loading ────────────────────────────────────────────────────────────────
  if (status === "loading" || profileLoading || !profile) {
    return (
      <div className="flex flex-col items-center gap-4 rounded-xl border-2 border-gray-300 p-8 shadow-md">
        <p className="animate-pulse text-gray-500">Loading profile…</p>
      </div>
    );
  }

  // ── Signed in ──────────────────────────────────────────────────────────────
  return (
    <div className="flex flex-col items-center gap-6 rounded-xl border-2 border-gray-300 p-8 shadow-md">
      {/* Avatar */}
      {profile.image && (
        <Image
          src={profile.image}
          alt={`${profile.name ?? "User"}'s GitHub avatar`}
          width={96}
          height={96}
          className="rounded-full border-2 border-purple-300"
        />
      )}

      {/* Display name */}
      {profile.name && (
        <h2 className="text-2xl font-bold text-gray-700">{profile.name}</h2>
      )}

      {/* GitHub username */}
      {profile.username && (
        <a
          href={`https://github.com/${profile.username}`}
          target="_blank"
          rel="noreferrer"
          className="flex items-center gap-1 text-violet-500 underline decoration-dotted underline-offset-2 hover:text-violet-700"
        >
          {/* GitHub mark – same icon used in GitHubSignInButton */}
          <svg
            aria-hidden="true"
            className="h-4 w-4 fill-current"
            viewBox="0 0 24 24"
            xmlns="http://www.w3.org/2000/svg"
          >
            <path d="M12 0C5.37 0 0 5.373 0 12c0 5.303 3.438 9.8 8.205 11.387.6.113.82-.258.82-.577 0-.285-.01-1.04-.015-2.04-3.338.724-4.042-1.61-4.042-1.61-.546-1.387-1.333-1.756-1.333-1.756-1.089-.745.083-.729.083-.729 1.205.084 1.839 1.237 1.839 1.237 1.07 1.834 2.807 1.304 3.492.997.108-.775.418-1.305.762-1.604-2.665-.305-5.467-1.334-5.467-5.931 0-1.311.469-2.381 1.236-3.221-.124-.303-.535-1.524.117-3.176 0 0 1.008-.322 3.301 1.23A11.509 11.509 0 0 1 12 5.803c1.02.005 2.047.138 3.006.404 2.291-1.552 3.297-1.23 3.297-1.23.653 1.653.242 2.874.118 3.176.77.84 1.235 1.911 1.235 3.221 0 4.609-2.807 5.624-5.479 5.921.43.372.823 1.102.823 2.222 0 1.606-.015 2.896-.015 3.286 0 .322.216.694.825.576C20.565 21.795 24 17.298 24 12c0-6.627-5.373-12-12-12z" />
          </svg>
          @{profile.username}
        </a>
      )}

      {/* Email */}
      {profile.email && (
        <p className="text-sm text-gray-500">{profile.email}</p>
